<?php
namespace App\Domain\Characters\Progression\Data;
final class CharacterProgressionResult{private $beforeExperience;private $afterExperience;private $beforeLevel;private $afterLevel;public function __construct(int $beforeExperience,int $afterExperience,int $beforeLevel,int $afterLevel){if($afterExperience<$beforeExperience||$afterLevel<$beforeLevel)throw new \InvalidArgumentException('Progression cannot decrease.');$this->beforeExperience=$beforeExperience;$this->afterExperience=$afterExperience;$this->beforeLevel=$beforeLevel;$this->afterLevel=$afterLevel;}public function toArray(){return['experience_before'=>$this->beforeExperience,'experience_after'=>$this->afterExperience,'experience_gained'=>$this->afterExperience-$this->beforeExperience,'level_before'=>$this->beforeLevel,'level_after'=>$this->afterLevel,'levels_gained'=>$this->afterLevel-$this->beforeLevel];}}
